import{_ as n,o as a,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Connecting Notes to Training Plans","description":"","frontmatter":{},"headers":[],"relativePath":"coach-notes/training-plans.md","filePath":"coach-notes/training-plans.md"}'),o={name:"coach-notes/training-plans.md"};function r(s,e,l,c,p,g){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="connecting-notes-to-training-plans" tabindex="-1">Connecting Notes to Training Plans <a class="header-anchor" href="#connecting-notes-to-training-plans" aria-label="Permalink to &quot;Connecting Notes to Training Plans&quot;">​</a></h1><p>Coach notes and training plans are connected throughout the app. Observations captured in notes drive training plan creation, and training plans reference note history when evaluating progress.</p><h2 id="creating-plans-from-note-processing" tabindex="-1">Creating Plans from Note Processing <a class="header-anchor" href="#creating-plans-from-note-processing" aria-label="Permalink to &quot;Creating Plans from Note Processing&quot;">​</a></h2><p>After running <strong>Process Notes with AI</strong> each extracted observation card has a <strong>Create Training Plan</strong> button. Tap it to open a pre-filled training plan with:</p><ul><li>The player already selected</li><li>The training area populated from the observation category</li><li>The focus area populated from the AI summary</li><li>The original note in the plan notes field</li></ul><p>Edit the plan to add specific objectives and drill references, then save.</p><h2 id="notes-in-training-plan-detail" tabindex="-1">Notes in Training Plan Detail <a class="header-anchor" href="#notes-in-training-plan-detail" aria-label="Permalink to &quot;Notes in Training Plan Detail&quot;">​</a></h2><p>When viewing a training plan detail you can see all notes tagged to that player and area. This gives context for how the issue developed and what approaches have been tried.</p><h2 id="report-card-connection" tabindex="-1">Report Card Connection <a class="header-anchor" href="#report-card-connection" aria-label="Permalink to &quot;Report Card Connection&quot;">​</a></h2><p>When generating a player report card the app includes:</p><ul><li>Active training plans</li><li>Coach notes from the selected date range (optional — you select whether to include raw notes)</li><li>AI-summarized observations (when AI processing was used)</li></ul><p>This makes report cards more specific and useful — families see not just stats but the coaching context behind the development priorities.</p><h2 id="note-tagging" tabindex="-1">Note Tagging <a class="header-anchor" href="#note-tagging" aria-label="Permalink to &quot;Note Tagging&quot;">​</a></h2><p>Notes can be manually tagged to specific training plans. When reviewing a plan tap <strong>Add Note</strong> to attach an existing note or create a new one directly in context. Tagged notes appear in the plan&#39;s activity feed in chronological order.</p>',14)])])}const u=n(o,[["render",r]]);export{h as __pageData,u as default};
